Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port. Pair it with the official C# MCP SDK client.

```csharp
// 1. Add these packages to your test project:
//    Microsoft.AspNetCore.Mvc.Testing
//    ModelContextProtocol  (official C# MCP SDK)

// 2. Create a fixture
using Microsoft.AspNetCore.Mvc.Testing;
using ModelContextProtocol.Client;
using ModelContextProtocol.Protocol.Transport;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly WebApplicationFactory<Program> _factory;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _factory = factory;
    }

    [Fact]
    public async Task ListTools_ReturnsExpectedTools()
    {
        // WebApplicationFactory gives you an in-memory HttpClient
        var httpClient = _factory.CreateClient();

        // Use SseClientTransport pointed at your MCP endpoint
        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/mcp/sse"),
                Name = "test-client"
            },
            httpClient);          // ← pass the in-memory client

        await using var mcpClient = await McpClientFactory.CreateAsync(
            transport,
            cancellationToken: CancellationToken.None);

        // Now exercise the full MCP protocol
        var tools = await mcpClient.ListToolsAsync();
        Assert.NotEmpty(tools);
        Assert.Contains(tools, t => t.Name == "my-tool");
    }

    [Fact]
    public async Task CallTool_ReturnsResult()
    {
        var httpClient = _factory.CreateClient();
        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/mcp/sse"),
                Name = "test-client"
            },
            httpClient);

        await using var mcpClient = await McpClientFactory.CreateAsync(transport);

        var result = await mcpClient.CallToolAsync(
            "my-tool",
            new Dictionary<string, object?> { ["input"] = "hello" });

        Assert.False(result.IsError);
        Assert.Contains(result.Content, c => c.Text!.Contains("expected output"));
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your real `Program` / `Startup` in-process — no port, no process, full middleware pipeline.
- Pass the factory's `HttpClient` directly to `SseClientTransport` so all HTTP stays in-memory.
- If your server uses **Streamable HTTP** instead of SSE, use `StreamableHttpClientTransport` with the same pattern.
- Override services via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test databases, mock auth, etc.
- Adjust the endpoint path (`/mcp/sse`, `/mcp`) to match your server's mapping.
